{
  "summary": "This paper systematically quantifies the impact of exposure bias in MLE-trained auto-regressive language models for open-ended generation by proposing two novel metrics (EB-M and EB-C) and conducting extensive experiments. The results show that exposure bias has a minor practical effect, with models able to recover from prefix mismatches and only small gains observed when conditioning on ground-truth prefixes.",
  "strengths": [
    {
      "point": "Systematic quantification of exposure bias impact using novel metrics",
      "evidence": "Introduction of EB-M and EB-C metrics measuring quality, diversity, and consistency differences between data and model prefixes."
    },
    {
      "point": "Comprehensive experimental evaluation including qualitative, quantitative, and human studies",
      "evidence": "Experiments on Transformer-XL and LSTM models with prefix-switching, synthetic EB-C setup, and crowd-sourced human evaluation."
    },
    {
      "point": "Insightful finding that MLE-trained models can self-recover from prefix distortions",
      "evidence": "Prefix-switching experiments show no incremental degradation even with shuffled or random prefixes."
    },
    {
      "point": "Challenging the widely held assumption that exposure bias severely degrades generation quality",
      "evidence": "Minimal relative gains (~1-2%) when removing training-generation discrepancy and stable EB-C values across prefix lengths."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison of proposed metrics to prior exposure bias measures",
      "evidence": "Lack of discussion or empirical comparison to existing quantitative metrics like scheduled sampling discrepancies."
    },
    {
      "point": "Methodological assumptions not rigorously tested",
      "evidence": "The 'comfortable zone' hypothesis is only qualitatively supported without systematic ablations varying mismatch severity or model capacity."
    },
    {
      "point": "Synthetic EB-C setup may not reflect real-world prefix distribution mismatches",
      "evidence": "EB-C relies on a smaller model trained on samples from a larger model rather than real data-model prefix differences."
    },
    {
      "point": "Limited diversity of models and datasets restricts generalizability",
      "evidence": "Experiments only on Transformer-XL and LSTM trained on wiki-103; no evaluation on GPT-style models or domain-specific corpora."
    },
    {
      "point": "Human evaluation details are sparse and potentially unreliable",
      "evidence": "No information on number of raters, inter-rater agreement, or statistical significance testing."
    },
    {
      "point": "Reproducibility hindered by missing hyperparameter details and lack of code release",
      "evidence": "No reported learning rates, batch sizes, training epochs, or code/data release statements."
    },
    {
      "point": "Clarity issues in defining and computing EB-M and EB-C metrics",
      "evidence": "Formulas and normalization procedures are vague and scattered without consolidated formal definitions."
    },
    {
      "point": "Limited scope excluding conditional generation tasks and domain shift scenarios",
      "evidence": "No experiments or discussion on exposure bias in tasks like machine translation or under domain shifts."
    }
  ],
  "questions": [
    {
      "question": "How do EB-M and EB-C metrics compare quantitatively to existing exposure bias measures?",
      "motivation": "Understanding relative advantages or complementarities is important to assess the novelty and utility of the proposed metrics."
    },
    {
      "question": "Does the self-recovery ability of models hold for larger-scale architectures and longer generation horizons?",
      "motivation": "Current experiments are limited to Transformer-XL and LSTM on wiki-103; modern large LMs may behave differently."
    },
    {
      "question": "How would exposure bias manifest in conditional generation tasks or under domain shifts?",
      "motivation": "Extending findings beyond open-ended generation is critical for broader applicability."
    },
    {
      "question": "Can more rigorous human evaluation with detailed protocols confirm the small observed differences?",
      "motivation": "Reliable human judgments are essential to validate the practical significance of exposure bias effects."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
